import { GoogleGenAI } from "@google/genai";

// Initialize the Google GenAI client
// The API key is obtained from the environment variable process.env.API_KEY
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Generates a concise physics explanation using gemini-3-flash-preview.
 */
export const generatePhysicsExplanation = async (
  topic: string, 
  velocity: number, 
  gamma: number
): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{
        parts: [{
          text: `Explain the concept of ${topic} in the context of Special Relativity. 
          Specifically, explain what happens when an object travels at ${velocity * 100}% the speed of light (max 0.999c), 
          resulting in a Lorentz factor (gamma) of ${gamma.toFixed(2)}. 
          Keep the explanation under 150 words, engaging, and strictly scientifically accurate. 
          Use simple analogies suitable for a university student.`
        }]
      }],
      config: {
        temperature: 0.7,
        topP: 0.95,
      }
    });

    // Access the text property directly from the GenerateContentResponse object
    return response.text || "I couldn't generate an explanation at this moment.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Error connecting to the relativity database (AI service unavailable).";
  }
};

/**
 * Advanced persona-based chat interaction using gemini-3-pro-preview.
 */
export const chatWithEinstein = async (history: {role: string, parts: {text: string}[]}[], message: string): Promise<string> => {
    try {
        const chat = ai.chats.create({
            model: 'gemini-3-pro-preview',
            config: {
                systemInstruction: `You are Albert Einstein, the physicist who revolutionized our understanding of space and time. 
                You are helpful, witty, and deeply philosophical. You speak with a gentle authority. 
                When explaining concepts, use thought experiments (Gedankenexperiments).
                Keep responses concise and conversational. Do not use complex LaTeX; use standard mathematical notation (e.g., E=mc^2).
                If the user asks about something unrelated to physics or science, gently bring the conversation back to the beauty of the universe.`,
            },
            history: history
        });

        const result = await chat.sendMessage({ message });
        // Correctly accessing the text property from the response object
        return result.text || "I am currently lost in thought about the cosmological constant.";
    } catch (error) {
        console.error("Gemini Chat Error:", error);
        return "My apologies, I seem to have lost my train of thought. Space-time is quite complex! (AI service error).";
    }
}

import React, { useState } from 'react';
import { Button } from './Button';
import { CheckCircle, XCircle, Award, RotateCcw, HelpCircle } from 'lucide-react';
import { usePageTracking, useAnalytics } from '../contexts/AnalyticsContext';
import { db } from '../services/databaseService';

interface Question {
