export const AnalyticsProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const currentPageRef = useRef<string | null>(null);
  const pageEnterTimeRef = useRef<number>(Date.now());

  const trackPageView = (pageName: string) => {
    const now = Date.now();

    if (currentPageRef.current) {
      const duration = (now - pageEnterTimeRef.current) / 1000;
      db.logEvent({
        eventType: 'DWELL_TIME',
        target: currentPageRef.current,
        value: duration
      });
    }

    currentPageRef.current = pageName;
    pageEnterTimeRef.current = now;

    db.logEvent({
      eventType: 'PAGE_VIEW',
      target: pageName
    });
  };

  const trackClick = (buttonId: string) => {
    db.logEvent({
      eventType: 'CLICK',
      target: buttonId
    });
  };

  const trackSlider = (sliderId: string, finalValue: number) => {
    db.logEvent({
      eventType: 'SLIDER_CHANGE',
      target: sliderId,
      value: finalValue
    });
  };

  const trackARInteraction = (featureId: string, objectId: string) => {
     db.logEvent({
         eventType: 'AR_INTERACTION',
         target: featureId,
         metadata: { objectId, timestamp: new Date().toISOString() }
     });
  };

  const trackVoiceInteraction = (persona: VoicePersona, text: string) => {
    db.logEvent({
      eventType: 'VOICE_INTERACTION',
      target: persona,
      value: text.length,
      metadata: { 
        text_snippet: text.substring(0, 100), // Log first 100 chars
        timestamp: new Date().toISOString() 
      }
    });
  };

  useEffect(() => {
    return () => {
      if (currentPageRef.current) {
        const duration = (Date.now() - pageEnterTimeRef.current) / 1000;
        db.logEvent({
            eventType: 'DWELL_TIME',
            target: currentPageRef.current,
            value: duration
        });
      }
    };
  }, []);

  return (
    <AnalyticsContext.Provider value={{ trackPageView, trackClick, trackSlider, trackARInteraction, trackVoiceInteraction }}>
      {children}
    </AnalyticsContext.Provider>
  );
};

export const useAnalytics = () => {
  const context = useContext(AnalyticsContext);
  if (!context) throw new Error('useAnalytics must be used within an AnalyticsProvider');
  return context;
};

export const usePageTracking = (pageName: string) => {
  const { trackPageView } = useAnalytics();
  useEffect(() => {
    trackPageView(pageName);
  }, [pageName]);
};

import React, { useState } from 'react';
import { Volume2, VolumeX } from 'lucide-react';
import { speakExplanation } from '../services/ttsService';
import { VoicePersona } from '../types';
import { useAnalytics } from '../contexts/AnalyticsContext';

interface SpeechControlProps {
  text: string;
}

export const SpeechControl: React.FC<SpeechControlProps> = ({ text }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [persona, setPersona] = useState<VoicePersona>('SISTER');
  const { trackVoiceInteraction } = useAnalytics();

  const handleSpeak = async () => {
    if (isPlaying) return;

    // Log the interaction with full text context
    trackVoiceInteraction(persona, text);

    setIsPlaying(true);
    await speakExplanation(text, persona);
    setIsPlaying(false);
  };

  return (
    <div className="flex items-center gap-3 mt-4 bg-black/20 p-2 rounded-lg w-full">
       <div className="text-xs text-slate-400 font-bold uppercase mr-2">Narrator:</div>

       <div className="flex gap-2">
         <button 
            type="button"
            onClick={() => setPersona('HEADMASTER')}
            className={`px-2 py-1 text-xs rounded border transition-colors ${persona === 'HEADMASTER' ? 'bg-cyan-900 border-cyan-500 text-white' : 'bg-space-800 border-space-600 text-slate-400 hover:text-white'}`}
         >
            Headmaster
         </button>
         <button 
            type="button"
            onClick={() => setPersona('SISTER')}
            className={`px-2 py-1 text-xs rounded border transition-colors ${persona === 'SISTER' ? 'bg-pink-900 border-pink-500 text-white' : 'bg-space-800 border-space-600 text-slate-400 hover:text-white'}`}
         >
            Sister
         </button>
         <button 
            type="button"
            onClick={() => setPersona('REBEL')}
            className={`px-2 py-1 text-xs rounded border transition-colors ${persona === 'REBEL' ? 'bg-orange-900 border-orange-500 text-white' : 'bg-space-800 border-space-600 text-slate-400 hover:text-white'}`}
         >
            Rebel
         </button>
       </div>

       <div className="flex-1"></div>

       <button 
         type="button"
         onClick={handleSpeak}
         disabled={isPlaying}
         className="flex items-center gap-2 text-cyan-400 hover:text-cyan-300 disabled:opacity-50 transition-colors"
       >
          {isPlaying ? <VolumeX size={18} /> : <Volume2 size={18} />}
          <span className="text-sm font-bold">{isPlaying ? 'Speaking...' : 'Listen'}</span>
       </button>
    </div>
  );
};

