                return (
                    <div 
                        key={item.id}
                        className={`absolute inset-0 transition-all duration-1000 ease-[cubic-bezier(0.23,1,0.32,1)] transform ${
                            isActive 
                            ? 'opacity-100 translate-y-0 scale-100 rotate-0 pointer-events-auto' 
                            : 'opacity-0 translate-y-12 scale-90 rotate-2 pointer-events-none'
                        }`}
                    >
                        <div className={`h-full bg-gradient-to-br ${item.color} border border-white/10 backdrop-blur-xl rounded-[40px] p-10 flex flex-col shadow-2xl relative overflow-hidden group transition-all duration-500 hover:border-white/30`}>
                            <div className={`absolute top-0 right-0 p-40 opacity-10 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2 ${item.accent}`}></div>

                            <div className="mb-8 p-5 bg-black/40 rounded-3xl border border-white/10 w-fit shadow-inner">
                                {item.icon}
                            </div>

                            <div className="space-y-2 mb-6">
                              <h2 className="text-4xl font-black text-white">{item.title}</h2>
                              <div className="flex items-center gap-2">
                                <div className={`w-2 h-2 rounded-full ${item.accent} shadow-[0_0_8px_rgba(255,255,255,0.5)]`}></div>
                                <h3 className="text-lg font-medium text-white/70">{item.subtitle}</h3>
                              </div>
                            </div>

                            <p className="text-slate-300 text-lg leading-relaxed font-light mb-auto">
                                {item.desc}
                            </p>

                            <div className="flex items-center justify-between mt-12">
                                <div className="flex gap-3">
                                    {PARADOXES.map((_, i) => (
                                        <button 
                                            key={i}
                                            onClick={() => setActiveIdx(i)}
                                            className={`h-1.5 rounded-full transition-all duration-500 ${i === activeIdx ? 'w-10 bg-white' : 'w-2 bg-white/20'}`}
                                        />
                                    ))}
                                </div>
                                <div className="text-white/20 font-mono text-sm uppercase tracking-tighter">Paradox_0{item.id}</div>
                            </div>
                        </div>
                    </div>
                );
            })}
        </div>

      </div>

      {/* Floating UI element: Current Ship Stats */}
      <div className="absolute bottom-12 left-1/2 -translate-x-1/2 hidden md:flex items-center gap-12 px-8 py-4 bg-black/40 backdrop-blur-md rounded-full border border-white/5 animate-bounce">
         <div className="flex items-center gap-3">
            <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
            <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Inertial Frame: Stable</span>
         </div>
         <div className="flex items-center gap-3">
            <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Physics Core: Active</span>
         </div>
         <div className="flex items-center gap-3">
            <Binary size={14} className="text-cyan-400" />
            <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Analysis Engine: Online</span>
         </div>
      </div>

      <style>{`
        .perspective-1000 {
          perspective: 1000px;
        }
      `}</style>
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";

// Initialize the Google GenAI client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Generates a concise physics explanation using gemini-3-flash-preview.
 */
export const generatePhysicsExplanation = async (
  topic: string, 
  velocity: number, 
  gamma: number
): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{
        parts: [{
          text: `Explain the concept of ${topic} in the context of Special Relativity. 
          Specifically, explain what happens when an object travels at ${velocity * 100}% the speed of light (max 0.999c), 
          resulting in a Lorentz factor (gamma) of ${gamma.toFixed(2)}. 
          Keep the explanation under 150 words, engaging, and strictly scientifically accurate. 
          Use simple analogies suitable for a university student.`
        }]
      }],
      config: {
        temperature: 0.7,
        topP: 0.95,
      }
    });

    return response.text || "I couldn't generate an explanation at this moment.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Error connecting to the relativity database (AI service unavailable).";
  }
};

/**
 * Chats with the Albert Einstein persona using gemini-3-pro-preview for complex reasoning.
 */
// Fix: Added missing chatWithEinstein function to support ChatTutor component
export const chatWithEinstein = async (
  history: { role: 'user' | 'model'; parts: { text: string }[] }[],
  message: string
): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: [
        ...history,
        { role: 'user', parts: [{ text: message }] }
      ],
      config: {
        systemInstruction: "You are Albert Einstein, a digital projection of his legendary mind. Explain concepts of special relativity with your characteristic wisdom, humility, and clear analogies (like riding on a beam of light). Be encouraging and curious about the explorer's questions. Keep responses relatively concise and suitable for a university student. Avoid excessive mathematical formalism unless explicitly asked.",
        temperature: 0.8,
        topP: 0.95,
      }
    });

    return response.text || "I am pondering the deep equations of our universe. Please try again in a moment.";
  } catch (error) {
    console.error("Einstein Chat Error:", error);
    return "The space-time continuum seems a bit noisy right now. My apologies, fellow explorer. Let us try again shortly.";
  }
};
